-- Phase 9 hardening: align HR table SELECT policies with get_hr_operational_summary domain gate.
-- Viewer/contractor must not read hr_items / hr_payments / hr_item_assignees directly merely because
-- finance visibility is detail; match public.can_access_hr_domain(project_id) (owner/co_owner only).

drop policy if exists hr_items_select on public.hr_items;
create policy hr_items_select on public.hr_items
for select
to authenticated
using (
  public.can_access_project(project_id)
  and public.can_view_sensitive_detail(project_id)
  and public.can_access_hr_domain(project_id)
);

drop policy if exists hr_payments_select on public.hr_payments;
create policy hr_payments_select on public.hr_payments
for select
to authenticated
using (
  public.can_access_project(project_id)
  and public.can_view_sensitive_detail(project_id)
  and public.can_access_hr_domain(project_id)
);

drop policy if exists hr_item_assignees_select on public.hr_item_assignees;
create policy hr_item_assignees_select on public.hr_item_assignees
for select
to authenticated
using (
  exists (
    select 1
    from public.hr_items hi
    where hi.id = hr_item_id
      and public.can_access_project(hi.project_id)
      and public.can_access_hr_domain(hi.project_id)
  )
);
